In Part 3 (“Mastering Angular Overlays: Building a Stacking Toast System with Hover Controls”), we tackled global, viewport-anchored notifications with non-overlapping stacking mechanics.
While toasts floating at screen boundaries provide broad status updates, UI design frequently demands contextual, highly targeted micro-overlays: Tooltips.
Unlike static modals or detached toast queues, tooltips live directly attached to host elements. They face distinct operational hurdles:

• Dynamic Viewport Adaptability: If a tooltip configured to open above an element hits the top edge of the screen, it must automatically pivot below the anchor without breaking host state.

• Minimal Execution Overhead: Hover triggers fire repeatedly. The overlay creation pathway must avoid heavy template lifecycle overhead and deprecated host binding APIs.

• Flexible Rendering: The tooltip must support plain string labels as well as complex TemplateRef structures with equal type safety.
In this article, we extend our core overlay abstraction (BaseOverlayService and BaseOverlayRef) to construct a flexible, boundary-aware tooltip architecture using modern Angular Signals and the CDK FlexibleConnectedPositionStrategy.
Step 1: Mapping Connected Overlay Positions
Connected overlays depend on an anchor point (origin) and an overlay point (overlay). To support automatic position flipping, we specify fallback orientations in a central map:
// tooltip-types.ts
import { ConnectedPosition } from '@angular/cdk/overlay';export type TooltipPosition = 'top' | 'bottom' | 'left' | 'right';
export const POSITION_MAP: Record<TooltipPosition, ConnectedPosition> = {
top: {
originX: 'center', originY: 'top',
overlayX: 'center', overlayY: 'bottom',
offsetY: -8, panelClass: 'tooltip-top',
},
bottom: {
originX: 'center', originY: 'bottom',
overlayX: 'center', overlayY: 'top',
offsetY: 8, panelClass: 'tooltip-bottom',
},
left: {
originX: 'start', originY: 'center',
overlayX: 'end', overlayY: 'center',
offsetX: -8, panelClass: 'tooltip-left',
},
right: {
originX: 'end', originY: 'center',
overlayX: 'start', overlayY: 'center',
offsetX: 8, panelClass: 'tooltip-right',
},
};
When building our position strategy, we put the user’s preferred choice first, followed by all remaining positions as ordered fallback steps.
Step 2: Extending the Overlay Ref with Reactive States
We extend BaseOverlayRef to attach lifecycle signals (isOpening, isOpen, isClosing, isClosed). This allows container host classes to animate out cleanly before destroying the CDK instance:
// tooltip-ref.ts
import { OverlayRef } from '@angular/cdk/overlay';
import { signal } from '@angular/core';
import { BaseOverlayRef } from '../../overlay/base-overlay-ref';
import { TooltipConfig } from './tooltip-config';export type TooltipState = 'opening' | 'open' | 'closing' | 'closed';
export class TooltipRef<T = unknown> extends BaseOverlayRef<TooltipConfig> {
public componentInstance!: T;
private readonly _state = signal<TooltipState>('opening');
readonly isOpening = () => this._state() === 'opening';
readonly isOpen = () => this._state() === 'open';
readonly isClosing = () => this._state() === 'closing';
readonly isClosed = () => this._state() === 'closed';
constructor(overlayRef: OverlayRef, config: TooltipConfig) {
super(overlayRef, config);
setTimeout(() => {
if (this._state() === 'opening') {
this._state.set('open');
}
}, 16);
}
override close(): void {
if (this._state() === 'closing' || this._state() === 'closed') return;
this._state.set('closing');
setTimeout(() => {
this._state.set('closed');
super.close();
}, this.exitAnimationDuration);
}
}
Step 3: Modern Signal-Based Host Container
Rather than using deprecated @HostBinding('class') decorators, we bind dynamic host attributes and classes through the @Component configuration host object. We expose a position Signal that reflects real-time positional changes directly to CSS rules:
// tooltip-container.ts
import { ChangeDetectionStrategy, Component, inject, signal, TemplateRef, ViewEncapsulation } from '@angular/core';
import { NgTemplateOutlet } from '@angular/common';
import { TooltipRef } from '../tooltip-ref';
import { TOOLTIP_CONFIG } from '../tooltip-tokens';
import { TooltipPosition } from '../tooltip-types';@Component({
selector: 'app-tooltip-container',
standalone: true,
imports: [NgTemplateOutlet],
templateUrl: './tooltip-container.html',
styleUrl: './tooltip-container.scss',
changeDetection: ChangeDetectionStrategy.OnPush,
encapsulation: ViewEncapsulation.None,
host: {
tabindex: '-1',
'[attr.id]': '_config.id',
'[class]': '`tooltip-${position()}`',
'[class.opening]': '_tooltipRef.isOpening()',
'[class.open]': '_tooltipRef.isOpen()',
'[class.closing]': '_tooltipRef.isClosing()',
'[class.closed]': '_tooltipRef.isClosed()',
'[style.--tooltip-enter-duration]': '`${_tooltipRef.enterAnimationDuration}ms`',
'[style.--tooltip-exit-duration]': '`${_tooltipRef.exitAnimationDuration}ms`',
},
})
export class TooltipContainer {
readonly _config = inject(TOOLTIP_CONFIG);
readonly _tooltipRef = inject(TooltipRef);
readonly position = signal<TooltipPosition>('top');
get template(): TemplateRef<unknown> | null {
return this._config.content instanceof TemplateRef ? this._config.content : null;
}
get text(): string | null {
return typeof this._config.content === 'string' ? this._config.content : null;
}
}
Step 4: Connecting the Tooltip Service & Handling Layout Flips
The TooltipService integrates directly with our base BaseOverlayService. Inside attachContent, we subscribe to strategy.positionChanges. Whenever the CDK flips the overlay due to viewport constraints, we update containerRef.instance.position, instantly applying the corresponding styling and arrow orientation rules:
// tooltip-service.ts
import { ElementRef, inject, Injectable } from '@angular/core';
import { FlexibleConnectedPositionStrategy, OverlayConfig, OverlayPositionBuilder } from '@angular/cdk/overlay';
import { _IdGenerator } from '@angular/cdk/a11y';
import { TooltipRef } from './tooltip-ref';
import { TooltipConfig } from './tooltip-config';
import { TOOLTIP_CONFIG } from './tooltip-tokens';
import { POSITION_MAP, TooltipPosition } from './tooltip-types';
import { TooltipContainer } from './tooltip-container';
import { BaseOverlayService } from '../../overlay/base-overlay-service';@Injectable({ providedIn: 'root' })
export class TooltipService extends BaseOverlayService<TooltipRef> {
private readonly positionBuilder = inject(OverlayPositionBuilder);
private readonly _idGenerator = inject(_IdGenerator);
override open(config: TooltipConfig, elementRef: ElementRef): TooltipRef {
const _config = { ...new TooltipConfig(), ...config };
_config.id = config?.id || this._idGenerator.getId('tooltip-');
const overlayConfig = this._overlayConfigBuilder(elementRef, _config.position);
return this.openOverlay(
TooltipContainer,
{
container: TooltipContainer,
config: _config,
createRef: (overlayRef, cfg) => new TooltipRef(overlayRef, cfg),
providers: (ref, cfg) => [
{ provide: TooltipRef, useValue: ref },
{ provide: TOOLTIP_CONFIG, useValue: cfg },
],
attachContent: (containerRef, component, config, ref) => {
ref.componentInstance = containerRef.instance;
if (_config.position) {
containerRef.instance.position.set(_config.position);
}
const strategy = overlayConfig.positionStrategy as FlexibleConnectedPositionStrategy;
strategy.positionChanges.subscribe((pos) => {
const pair = pos.connectionPair;
if (pair.overlayY === 'bottom') {
containerRef.instance.position.set('top');
} else if (pair.overlayY === 'top') {
containerRef.instance.position.set('bottom');
} else if (pair.overlayX === 'end') {
containerRef.instance.position.set('left');
} else if (pair.overlayX === 'start') {
containerRef.instance.position.set('right');
}
});
},
},
overlayConfig,
);
}
protected _overlayConfigBuilder(
elementRef: ElementRef,
preferred: TooltipPosition = 'top',
): OverlayConfig {
const positions = [
POSITION_MAP[preferred],
...Object.keys(POSITION_MAP)
.filter((p) => p !== preferred)
.map((p) => POSITION_MAP[p as TooltipPosition]),
];
const positionStrategy = this.positionBuilder
.flexibleConnectedTo(elementRef)
.withPositions(positions)
.withPush(true)
.withViewportMargin(8);
return new OverlayConfig({
positionStrategy,
scrollStrategy: this._overlay.scrollStrategies.reposition(),
});
}
}
Step 5: High-Performance Declarative Directive
Finally, we expose this functionality using a lightweight directive powered by Angular’s Signal inputs:
// tooltip.directive.ts
import { Directive, ElementRef, HostListener, inject, input, TemplateRef } from '@angular/core';
import { TooltipService } from './tooltip-service';
import { TooltipRef } from './tooltip-ref';
import { TooltipPosition } from './tooltip-types';@Directive({
selector: '[tooltip]',
standalone: true,
})
export class TooltipDirective {
private readonly element = inject(ElementRef);
private readonly tooltipService = inject(TooltipService);
private tooltipRef: TooltipRef | undefined = undefined;
readonly content = input<string | TemplateRef<unknown>>('', { alias: 'tooltip' });
readonly position = input<TooltipPosition>('top');
@HostListener('mouseenter')
show(): void {
if (this.tooltipRef) return;
this.tooltipRef = this.tooltipService.open(
{
content: this.content(),
position: this.position(),
},
this.element,
);
}
@HostListener('mouseleave')
hide(): void {
this.tooltipRef?.close();
this.tooltipRef = undefined;
}
}
